app = FastAPI(lifespan=lifespan)

security = HTTPBearer(auto_error=False)

def hash_token(token: str) -> str:
    return hashlib.sha256(token.encode()).hexdigest()

class TokenValidator:
    def __init__(self, redis_client: Redis):
        self.redis_client = redis_client
        self.token_prefix = "oauth_token:"
    
    def validate_token(self, token: str) -> bool:
        if not token or len(token) < 32:
            return False
        
        try:
            token_hash = hash_token(token)
            token_key = f"{self.token_prefix}{token_hash}"
            
            exists = self.redis_client.exists(token_key)
            return bool(exists)
        except RedisError:
            raise HTTPException(
                status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
                detail="Token validation service unavailable"
            )
        except Exception:
            raise HTTPException(
                status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
                detail="Internal server error during token validation"
            )
    
    def get_token_data(self, token: str) -> Optional[dict]:
        try:
            token_hash = hash_token(token)
            token_key = f"{self.token_prefix}{token_hash}"
            
            token_data = self.redis_client.hgetall(token_key)
            return token_data if token_data else None
        except RedisError:
            raise HTTPException(
                status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
                detail="Token validation service unavailable"
            )
        except Exception:
            raise HTTPException(
                status_code=status.HTTP_500_INTERNAL_SERVER_ERROR,
                detail="Internal server error during token retrieval"
            )

def get_token_validator() -> TokenValidator:
    if redis_client is None:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    return TokenValidator(redis_client)

async def validate_bearer_token(
    credentials: Optional[HTTPAuthorizationCredentials] = Security(security),
    validator: TokenValidator = Depends(get_token_validator)
) -> str:
    if credentials is None:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Missing authentication credentials",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    if credentials.scheme.lower() != "bearer":
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid authentication scheme",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    token = credentials.credentials
    
    if not validator.validate_token(token):
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Invalid or expired token",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    return token

async def get_current_user(
    token: str = Depends(validate_bearer_token),
    validator: TokenValidator = Depends(get_token_validator)
) -> dict:
    token_data = validator.get_token_data(token)
    
    if not token_data:
        raise HTTPException(
            status_code=status.HTTP_401_UNAUTHORIZED,
            detail="Could not retrieve token data",
            headers={"WWW-Authenticate": "Bearer"},
        )
    
    return token_data

