@app.post("/admin/token")
async def create_token(
    user_id: str,
    scopes: Optional[str] = None,
    ttl: int = 3600
):
    if not redis_client:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    
    token = secrets.token_urlsafe(32)
    token_hash = hash_token(token)
    token_key = f"oauth_token:{token_hash}"
    
    token_data = {
        "user_id": user_id,
        "scopes": scopes or "",
        "created_at": str(int(os.times().elapsed))
    }
    
    try:
        redis_client.hset(token_key, mapping=token_data)
        redis_client.expire(token_key, ttl)
        
        return {
            "token": token,
            "token_type": "bearer",
            "expires_in": ttl
        }
    except RedisError as e:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Failed to create token"
        )

@app.delete("/admin/token/{token}")
async def revoke_token(token: str):
    if not redis_client:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Redis connection not available"
        )
    
    try:
        token_hash = hash_token(token)
        token_key = f"oauth_token:{token_hash}"
        
        deleted = redis_client.delete(token_key)
        
        if deleted:
            return {"message": "Token revoked successfully"}
        else:
            raise HTTPException(
                status_code=status.HTTP_404_NOT_FOUND,
                detail="Token not found"
            )
    except RedisError:
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="Failed to revoke token"
        )